[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$ResetOneDrive,[switch]$ClearTeamsCache,[switch]$RestartServices,[switch]$Force,[string]$OutputPath="$env:USERPROFILE\Desktop\TeamsOneDriveRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append}
if(-not($ResetOneDrive-or$ClearTeamsCache-or$RestartServices)){throw'Choose at least one repair action.'}
Get-Process OneDrive,ms-teams,Teams -ErrorAction SilentlyContinue|Select Name,Id,Path|Export-Csv (Join-Path $OutputPath 'before-processes.csv') -NoTypeInformation
if($ClearTeamsCache){$p=Get-Process ms-teams,Teams -ErrorAction SilentlyContinue;if($p-and-not$Force){throw'Close Teams or use -Force.'};if($p){$p|Stop-Process -Force};$paths=@("$env:APPDATA\Microsoft\Teams","$env:LOCALAPPDATA\Packages\MSTeams_8wekyb3d8bbwe\LocalCache\Microsoft\MSTeams");foreach($x in $paths){if(Test-Path $x){$b=Join-Path $OutputPath ((Split-Path $x -Leaf)+'.txt');Get-ChildItem $x -Force -ErrorAction SilentlyContinue|Select FullName,Length,LastWriteTime|Out-File $b;if($PSCmdlet.ShouldProcess($x,'Clear Teams cache')){Get-ChildItem $x -Force -ErrorAction SilentlyContinue|Remove-Item -Recurse -Force -ErrorAction SilentlyContinue}}};L'Teams cache processed.'}
if($ResetOneDrive){$exe=@("$env:LOCALAPPDATA\Microsoft\OneDrive\OneDrive.exe","$env:ProgramFiles\Microsoft OneDrive\OneDrive.exe","${env:ProgramFiles(x86)}\Microsoft OneDrive\OneDrive.exe")|Where-Object{Test-Path $_}|Select-Object -First 1;if(-not$exe){throw'OneDrive.exe not found.'};if($PSCmdlet.ShouldProcess('OneDrive','Reset sync client')){Start-Process $exe '/reset' -Wait;Start-Sleep 5;Start-Process $exe;L'OneDrive reset completed.'}}
if($RestartServices){foreach($s in 'ClickToRunSvc','WpnService'){if(Get-Service $s -ErrorAction SilentlyContinue){if($PSCmdlet.ShouldProcess($s,'Restart service')){Restart-Service $s -Force;L"Restarted $s"}}}}
Get-Process OneDrive,ms-teams,Teams -ErrorAction SilentlyContinue|Select Name,Id,Path|Export-Csv (Join-Path $OutputPath 'after-processes.csv') -NoTypeInformation;L'Repair workflow finished.'